<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Payment Form</title>\n    <script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>\n    <script src="https://js.flutterwave.com/v3.js"></script>\n</head>\n<body>\n    <h1>Payment Form</h1>\n    <form id="paymentForm">\n        <label for="email">Email:</label>\n        <input type="email" id="email" name="email" required>\n        <br>\n        <label for="amount">Amount:</label>\n        <input type="number" id="amount" name="amount" required>\n        <br>\n        <button type="submit">Pay Now</button>\n    </form>\n    <div id="errorMessage" style="color: red;"></div>\n    <script>\n        $(document).ready(function() {\n            $('#paymentForm').on('submit', function(event) {\n                event.preventDefault();\n                const email = $('#email').val();\n                const amount = $('#amount').val();\n                FlutterwaveCheckout({\n                    public_key: 'YOUR_PUBLIC_KEY',  // Update with your public key\n                    tx_ref: \"tx-\" + Math.random().toString(36).substring(2, 15),\n                    amount: amount,\n                    currency: 'NGN',\n                    email: email,\n                    callback: function(data) {\n                        // Implement post-payment logic here\n                        console.log('Payment successful!', data);\n                    },\n                    on_close: function() {\n                        // Implement what to do when the modal is closed\n                    },\n                    // Customize the error handling\n                    onerror: function(error) {\n                        $('#errorMessage').text('Payment failed: ' + error.message);\n                    }\n                });\n            });\n        });\n    </script>\n</body>\n</html>\n